-- ============================================================
-- Reposiciona os geradores IDENTITY (achado F21)
--
-- As 4 tabelas abaixo têm ID «GENERATED BY DEFAULT ON NULL AS
-- IDENTITY» e o seed acima grava ID EXPLÍCITO. No Oracle, valor
-- explícito NÃO avança a sequence interna — ela ficaria em 1, e o
-- PRIMEIRO cadastro feito pela aplicação (que insere sem ID)
-- colidiria com o seed: ORA-00001 na chave primária.
--
-- START WITH LIMIT VALUE recomeça o gerador em MAX(ID) + 1.
-- (Só estas 4: as tabelas PES_* usam SYS_GUID(), não IDENTITY.)
--
-- CAD_SALA é realinhada MAIS UMA VEZ pelo changelog 043: o
-- changeset 007 roda depois deste script e insere a sala
-- 'Demais Salas' com ID explícito (11), desalinhando o gerador
-- outra vez.
-- ============================================================
ALTER TABLE CAD_SALA                  MODIFY (ID GENERATED BY DEFAULT ON NULL AS IDENTITY (START WITH LIMIT VALUE));
ALTER TABLE CAD_COMISSAO              MODIFY (ID GENERATED BY DEFAULT ON NULL AS IDENTITY (START WITH LIMIT VALUE));
ALTER TABLE FRM_CHECKLIST_ITEM_TIPO   MODIFY (ID GENERATED BY DEFAULT ON NULL AS IDENTITY (START WITH LIMIT VALUE));
ALTER TABLE FRM_CHECKLIST_SALA_CONFIG MODIFY (ID GENERATED BY DEFAULT ON NULL AS IDENTITY (START WITH LIMIT VALUE));
